"use client"

import { useContext, useEffect, useState } from "react"
import { ProfileContext } from "../../context/profile/ProfileContext"
import Spinner from "../layout/Spinner"
import axios from "axios"

const LinkedInPosts = () => {
  const { profile } = useContext(ProfileContext)
  const [linkedinData, setLinkedinData] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  useEffect(() => {
    const fetchLinkedInData = async () => {
      if (profile) {
        const linkedinPlatform = profile.platforms.find((p) => p.name === "LinkedIn")
        if (linkedinPlatform) {
          try {
            setLoading(true)
            const res = await axios.get("/api/linkedin/profile")

            if (res.data.success) {
              setLinkedinData(res.data.data)
            } else {
              setError({
                message: res.data.message || "Failed to fetch LinkedIn data",
                details: res.data.details || [],
              })
            }
          } catch (err) {
            console.error("Error fetching LinkedIn data:", err)
            setError({
              message: "Failed to connect to LinkedIn API",
              details: ["There was an error retrieving LinkedIn profile data"],
            })
          } finally {
            setLoading(false)
          }
        } else {
          setLoading(false)
        }
      }
    }

    fetchLinkedInData()
  }, [profile])

  if (loading) {
    return <Spinner />
  }

  if (!linkedinData) {
    return (
      <div className="bg-white p-4 rounded-lg shadow-md">
        <h3 className="text-xl font-semibold mb-2">LinkedIn Activity</h3>
        <p>Add your LinkedIn profile to see your activity here.</p>
      </div>
    )
  }

  // Format date
  const formatDate = (dateString) => {
    const options = { year: "numeric", month: "short", day: "numeric" }
    return new Date(dateString).toLocaleDateString(undefined, options)
  }

  return (
    <div className="bg-white p-4 rounded-lg shadow-md">
      <h3 className="text-xl font-semibold mb-4">LinkedIn Activity</h3>

      {linkedinData.dataSource && (
        <div className="bg-blue-50 p-2 rounded-md mb-4 text-xs text-blue-700">
          <p>Data source: {linkedinData.dataSource}</p>
          {linkedinData.note && <p className="mt-1">{linkedinData.note}</p>}
        </div>
      )}

      <div className="flex flex-col md:flex-row gap-4 mb-6">
        <div className="md:w-1/3">
          <div className="bg-gray-100 p-4 rounded-lg">
            <h4 className="font-semibold text-lg mb-2">{linkedinData.name}</h4>
            <p className="text-gray-600 mb-2">{linkedinData.headline}</p>
            <p className="text-gray-600 text-sm mb-3">{linkedinData.location}</p>

            <div className="grid grid-cols-2 gap-2 mt-4">
              <div className="bg-white p-2 rounded">
                <p className="text-sm text-gray-600">Connections</p>
                <p className="text-xl font-bold">{linkedinData.profileSummary?.connections || "N/A"}</p>
              </div>
              <div className="bg-white p-2 rounded">
                <p className="text-sm text-gray-600">Profile Views</p>
                <p className="text-xl font-bold">{linkedinData.profileSummary?.profileViews || "N/A"}</p>
              </div>
            </div>

            <a
              href={linkedinData.profileUrl}
              target="_blank"
              rel="noopener noreferrer"
              className="block mt-4 text-center bg-blue-600 text-white py-2 px-4 rounded hover:bg-blue-700"
            >
              View Full Profile
            </a>
          </div>
        </div>

        <div className="md:w-2/3">
          {linkedinData.about && (
            <div className="mb-4">
              <h4 className="font-semibold mb-2">About</h4>
              <p className="text-gray-700">
                {linkedinData.about.length > 200 ? `${linkedinData.about.substring(0, 200)}...` : linkedinData.about}
              </p>
            </div>
          )}

          {linkedinData.experiences && linkedinData.experiences.length > 0 && (
            <div className="mb-4">
              <h4 className="font-semibold mb-2">Experience</h4>
              <div className="space-y-2">
                {linkedinData.experiences.slice(0, 2).map((exp, index) => (
                  <div key={index} className="bg-gray-50 p-2 rounded">
                    <p className="font-medium">{exp.title}</p>
                    <p className="text-sm text-gray-600">{exp.company}</p>
                    <p className="text-xs text-gray-500">{exp.duration}</p>
                  </div>
                ))}
              </div>
            </div>
          )}

          {linkedinData.skills && linkedinData.skills.length > 0 && (
            <div>
              <h4 className="font-semibold mb-2">Skills</h4>
              <div className="flex flex-wrap gap-2">
                {linkedinData.skills.map((skill, index) => (
                  <span key={index} className="bg-blue-100 text-blue-800 px-2 py-1 rounded text-sm">
                    {skill}
                  </span>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>

      <h4 className="font-semibold mb-2">Recent Posts</h4>
      {linkedinData.posts && linkedinData.posts.length > 0 ? (
        <div className="space-y-4">
          {linkedinData.posts.map((post, index) => (
            <div key={index} className="border rounded-lg p-3">
              <p className="mb-2">{post.content}</p>
              <div className="flex justify-between text-sm text-gray-500 mb-2">
                <span>{formatDate(post.date)}</span>
                <div className="flex space-x-3">
                  <span>👍 {post.likes}</span>
                  <span>💬 {post.comments}</span>
                  <span>🔄 {post.shares}</span>
                </div>
              </div>
              {post.isArticle && (
                <div className="mt-2">
                  <span className="bg-blue-100 text-blue-800 text-xs px-2 py-1 rounded">Article</span>
                </div>
              )}
            </div>
          ))}
        </div>
      ) : (
        <div className="p-4 bg-gray-50 rounded-md">
          <p>No posts available.</p>
        </div>
      )}
    </div>
  )
}

export default LinkedInPosts
